SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW view_esteate_find (membership_no, member_name, member_surname, doc_no, coll_ref_type, cancel_status, land_address_no, province_name, title_deed, building_name, loan_contract_no) AS select           sc_mem_m_membership_registered.membership_no
, sc_mem_m_membership_registered.member_name
, sc_mem_m_membership_registered.member_surname
,tb.doc_no
,tb.coll_ref_type
,tb.cancel_status
,tb.land_address_no
,( SELECT PROVINCE_NAME FROM SC_MEM_M_UCF_PROVINCE WHERE PROVINCE_CODE = tb.province_code ) AS PROVINCE_NAME
,tb.title_deed
,tb.building_name
,tb.loan_contract_no  

from 
( 
  SELECT sc_lon_req_coll_law_head.membership_no,   
         sc_lon_req_coll_law_head.doc_no,  
         sc_lon_req_coll_law_head.coll_ref_type,
         sc_lon_req_coll_law_head.cancel_status,
         sc_lon_req_coll_law_land.land_address_no,   
         sc_lon_req_coll_law_land.province_code,   
         null  as title_deed ,
         null as building_name 
        ,( select max( loan_contract_no ) from sc_lon_m_contract_coll where status = '0' and ref_own_no = sc_lon_req_coll_law_head.doc_no )  as loan_contract_no

    FROM sc_lon_req_coll_law_head,   
         sc_lon_req_coll_law_land 
   WHERE  1=1   
and  sc_lon_req_coll_law_head.doc_no = sc_lon_req_coll_law_land.doc_no 


union all
 

  SELECT sc_lon_req_coll_law_head.membership_no,   
         sc_lon_req_coll_law_head.doc_no,   
         sc_lon_req_coll_law_head.coll_ref_type,
         sc_lon_req_coll_law_head.cancel_status,
         sc_lon_req_coll_law_condo.title_deed as land_address_no,   
         sc_lon_req_coll_law_condo.province_code,   
         sc_lon_req_coll_law_condo.address_no   as title_deed ,   
         sc_lon_req_coll_law_condo.building_name  
       ,( select max( loan_contract_no ) from sc_lon_m_contract_coll where status = '0' and ref_own_no = sc_lon_req_coll_law_head.doc_no )  as loan_contract_no

    FROM sc_lon_req_coll_law_head,      
         sc_lon_req_coll_law_condo  
   WHERE  1=1   
and  sc_lon_req_coll_law_head.doc_no = sc_lon_req_coll_law_condo.doc_no 

)  tb
,  sc_mem_m_membership_registered 
where sc_mem_m_membership_registered.membership_no = tb.membership_no
/*WHERE*/

--and sc_mem_m_membership_registered.membership_no = '000034'
order by tb.doc_no desc;

